class Solution:
    def minimumDiameterAfterMerge(self, edges1: List[List[int]], edges2: List[List[int]]) -> int:
        def build_tree(edges, n):
            tree = [[] for _ in range(n)]
            for a, b in edges:
                tree[a].append(b)
                tree[b].append(a)
            return tree

        def get_diameter(tree, n):
            def dfs(node, parent):
                max1 = 0
                max2 = 0
                for neighbor in tree[node]:
                    if neighbor != parent:
                        depth = dfs(neighbor, node)
                        if depth > max1:
                            max2 = max1
                            max1 = depth
                        elif depth > max2:
                            max2 = depth
                nonlocal diameter
                diameter = max(diameter, max1 + max2)
                return max1 + 1

            diameter = 0
            dfs(0, -1)
            return diameter

        def get_max_depth(tree, n):
            def dfs(node, parent, depth):
                max_depth = depth
                for neighbor in tree[node]:
                    if neighbor != parent:
                        max_depth = max(max_depth, dfs(neighbor, node, depth + 1))
                return max_depth

            return dfs(0, -1, 0)

        tree1 = build_tree(edges1, len(edges1) + 1)
        tree2 = build_tree(edges2, len(edges2) + 1)

        diameter1 = get_diameter(tree1, len(edges1) + 1)
        diameter2 = get_diameter(tree2, len(edges2) + 1)

        max_depth1 = get_max_depth(tree1, len(edges1) + 1)
        max_depth2 = get_max_depth(tree2, len(edges2) + 1)

        return max(diameter1, diameter2, max_depth1 + max_depth2 + 1)
